PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?participant WHERE {
  VALUES ?series {
    wd:Q15267 wd:Q15563 wd:Q25356 wd:Q19317
  }
  ?event wdt:P361 ?series .
  ?event wdt:P585 ?date .
  FILTER(YEAR(?date) = 1998)
  ?event wdt:P1344 ?participant .
  ?participant wdt:P735 ?givenName .
  FILTER(LCASE(?givenName) = "mark")
}
